const { Manifold, label, setCircularSegments } = api;
setCircularSegments(32);

function box(min, max) {
  const s = [max[0] - min[0], max[1] - min[1], max[2] - min[2]];
  const c = [(min[0] + max[0]) / 2, (min[1] + max[1]) / 2, (min[2] + max[2]) / 2];
  return Manifold.cube(s, true).translate(c);
}

// Arcade cabinet: Z-up, front facing -Y.
// Main body: x=-9..9, y=-5..5, z=0..28
const mainBody = box([-9, -5, 0], [9, 5, 28]);

// Control panel: protrudes forward at z=10-17
const ctrlPanel = box([-9, -8, 10], [9, -5, 17]);

// Marquee: protrudes forward at top z=28..34
const marqueeBox = box([-9, -8, 28], [9, -4, 34]);

// Top cap
const topCap = box([-9, -5, 34], [9, 5, 36]);

// Screen panel on front face
const screen = box([-6.5, -5.3, 18], [6.5, -3.5, 27.5]);

// Joystick on control panel
const joyStem = Manifold.cylinder(3.5, 0.9, 0.9, 16).translate([-3.5, -8.5, 12]);
const joyBall = Manifold.sphere(1.3, 16).translate([-3.5, -8.5, 15.5]);

// Buttons: 3 cylinders on control panel
const btn1 = Manifold.cylinder(0.7, 1.0, 1.0, 16).translate([0.5, -8.5, 14]);
const btn2 = Manifold.cylinder(0.7, 1.0, 1.0, 16).translate([2.5, -8.5, 14]);
const btn3 = Manifold.cylinder(0.7, 1.0, 1.0, 16).translate([4.5, -8.5, 14]);

// Coin slot
const coinSlot = box([-1.2, -5.3, 5], [1.2, -4.5, 6.2]);

// Key insight from boombox: include everything in base body EXCEPT what we want labeled.
// The base body (unlabeled) includes mainBody + ctrlPanel + topCap.
// marqueeBox, screen, joystick, buttons, coinSlot are added as LABELED shapes only.
// They must overlap base body by 0.5+ to keep 1 component.

const baseBody = mainBody.add(ctrlPanel).add(topCap);

return label(baseBody, 'body')
  .add(label(marqueeBox, 'marquee'))
  .add(label(screen, 'screen'))
  .add(label(joyStem.add(joyBall), 'joystick'))
  .add(label(btn1.add(btn2).add(btn3), 'buttons'))
  .add(label(coinSlot, 'coinslot'));
